<?php require_once __DIR__.'/includes/bootstrap.php'; requireLogin(); $st=$pdo->prepare('SELECT * FROM customer_orders WHERE user_id=? ORDER BY id DESC');$st->execute([currentUser()['id']]);$orders=$st->fetchAll(); include __DIR__.'/includes/header.php'; ?><main class='page-shell'><h1>My Orders</h1><?php foreach($orders as $o): ?><div class='cart-item'>Order #<?= $o['id']?> - <?= e($o['status'])?> - <?= formatPrice($o['total_amount'])?></div><?php endforeach; ?></main><?php include __DIR__.'/includes/footer.php'; ?>